('ONET-MATERIAL_MOVING_WORKERS_ALL_OTHER', 'source_onet_material_moving_workers_all_other', 'Material Moving Workers, All Other', 'Material Moving Workers, All Other is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'All material moving workers not listed separately.', ARRAY['Barge Loader','Board Stacker','Boat Hoist Operator Helper','Boat Loader','Boat Loader Helper','Bobbin Hauler','Bobbin Trucker','Brick Setter','Brick Wheeler','Bucket Operator','Bull Chain Operator','Cage Loader','Cage Unloader','Cager Operator','Canal Tender','Car Dropper','Car Dumper Operator','Car Mover','Car Runner','Car Shifter','Car Trimmer','Carrier','Cat Wagon Operator','Cement Boat and Barge Loader','Chain Hooker','Charge Machine Operator','Chip Unloader','Chute Loader','Clay Carman','Clay Transporter','Cloth Carrier','Cloth Hauler','Coal Carrier','Coal Equipment Operator','Coal Handler','Coal Screener','Coal Whipper','Coke Wheeler','Collector','Cone Trucker','Cooker Loader','Crane Chaser','Crane Follower','Crane Helper','Crane Hooker','Derrick Follower','Distributor','Ditch Tender','Dock Hand','Dope Worker']::text[], ARRAY['Material Moving Workers, All Other','Barge Loader','Board Stacker','Boat Hoist Operator Helper','Boat Loader','Boat Loader Helper','Bobbin Hauler','Bobbin Trucker','Brick Setter','Brick Wheeler','Bucket Operator','Bull Chain Operator','Cage Loader','Cage Unloader','Cager Operator','Canal Tender','Car Dropper','Car Dumper Operator','Car Mover','Car Runner','Car Shifter','Car Trimmer','Carrier','Cat Wagon Operator','Cement Boat and Barge Loader','Chain Hooker']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","Indi