('ONET-AIR_CREW_OFFICERS', 'source_onet_air_crew_officers', 'Air Crew Officers', 'Air Crew Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Perform and direct in-flight duties to ensure the successful completion of combat, reconnaissance, transport, and search and rescue missions. Duties include operating aircraft communications and radar equipment, such as establishing satellite linkages and jamming enemy communications capabilities; operating aircraft weapons and defensive systems; conducting preflight, in-flight, and postflight inspections of onboard equipment; and directing cargo and personnel drops.', ARRAY['Airdrop Systems Technician','Astronaut, Mission Specialist','Helicopter Officer','Naval Flight Officer, Airborne Reconnaissance Officer','Naval Flight Officer, Bombardier/Navigator','Naval Flight Officer, Electronic Warfare Officer','Naval Flight Officer, Qualified Supporting Arms Coordinator (Airborne)','Naval Flight Officer, Radar Intercept Officer','Naval Flight Officer, Weapons Systems Officer','Special Project Airborne Electronics Evaluator']::text[], ARRAY['Air Crew Officers','Airdrop Systems Technician','Astronaut, Mission Specialist','Helicopter Officer','Naval Flight Officer, Airborne Reconnaissance Officer','Naval Flight Officer, Bombardier/Navigator','Naval Flight Officer, Electronic Warfare Officer','Naval Flight Officer, Qualified Supporting Arms Coordinator (Airborne)','Naval Flight Officer, Radar Intercept Officer','Naval Flight Officer, Weapons Systems Officer','Special Project Airborne Electronics Evaluator']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-AIRCRAFT_LAUNCH_AND_RECOVERY_OFFICERS', 'source_onet_aircraft_launch_and_recovery_officers', 'Aircraft Launch and Recovery Officers', 'Aircraft Launch and Recovery Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Plan and direct the operation and maintenance of catapults, arresting gear, and associated mechanical, hydraulic, and control systems involved primarily in aircraft carrier takeoff and landing operations. Duties include supervision of readiness and safety of arresting gear, launching equipment, barricades, and visual landing aid systems; planning and coordinating the design, development, and testing of launch and recovery systems; preparing specifications for catapult and arresting gear installations; evaluating design proposals; determining handling equipment needed for new aircraft; preparing technical data and instructions for operation of landing aids; and training personnel in carrier takeoff and landing procedures.', ARRAY['Catapult and Arresting Gear Officer','Flight Deck Officer','Landing Signal Officer','V/STOL Landing Signal Officer']::text[], ARRAY['Aircraft Launch and Recovery Officers','Catapult and Arresting Gear Officer','Flight Deck Officer','Landing Signal Officer','V/STOL Landing Signal Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-ARMORED_ASSAULT_VEHICLE_OFFICERS', 'source_onet_armored_assault_vehicle_officers', 'Armored Assault Vehicle Officers', 'Armored Assault Vehicle Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Direct the operation of tanks, light armor, and amphibious assault vehicle units during combat situations on land or in aquatic environments. Duties include directing crew members in the operation of targeting and firing systems; coordinating the operation of advanced onboard communications and navigation equipment; directing the transport of personnel and equipment during combat; formulating and implementing battle plans, including the tactical employment of armored vehicle units; and coordinating with infantry, artillery, and air support units.', ARRAY['Armor Officer','Assault Amphibious Vehicle (AAV) Officer','Cavalry Officer','Light-Armored Reconnaissance Officer','Light-Armored Vehicle Officer','Tank Officer']::text[], ARRAY['Armored Assault Vehicle Officers','Armor Officer','Assault Amphibious Vehicle (AAV) Officer','Cavalry Officer','Light-Armored Reconnaissance Officer','Light-Armored Vehicle Officer','Tank Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-ARTILLERY_AND_MISSILE_OFFICERS', 'source_onet_artillery_and_missile_officers', 'Artillery and Missile Officers', 'Artillery and Missile Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Manage personnel and weapons operations to destroy enemy positions, aircraft, and vessels. Duties include planning, targeting, and coordinating the tactical deployment of field artillery and air defense artillery missile systems units; directing the establishment and operation of fire control communications systems; targeting and launching intercontinental ballistic missiles; directing the storage and handling of nuclear munitions and components; overseeing security of weapons storage and launch facilities; and managing maintenance of weapons systems.', ARRAY['Air Defense Artillery Officer','Ammunition Officer','Division Officer, Weapons Department','Division Officer, Weapons Department (Antisubmarine Weapons)','Division Officer, Weapons Department (Guided Missiles)','Division Officer, Weapons Department (Gunnery)','Field Artillery Officer','Field Artillery Senior Sergeant','Field Artillery Targeting Technician','Fire Control Officer (Surface-To-Air Missiles)','Ground Nuclear Weapons Assembly Officer','Guided Missile Test Officer, Air-Launched','HAWK Missile Air Defense Artillery','Low Altitude Air Defense Officer','Naval Gunfire Spotter','Naval Surface Fire Support Planner','Nuclear & Chemical Weapons Employment Officer','Nuclear Weapons Custodian','Ordnance Officer','PATRIOT Missile Air Defense Artillery','Short-Range Air Defense Artillery','Space And Missile Operations, Missile Combat Crew Officer','Strike Warfare/Missile Systems Officer','Strike Warfare/Missile Systems Officer (Surface-to-Air Missile)','Surface-to-Air Weapons Officer','Targeting Acquisition Officer','Weapons Military Characteristics Officer','Weapons Officer','Weapons Officer (Fleet Ballistic Missiles)','Weapons Officer, Naval Activity']::text[], ARRAY['Artillery and Missile Officers','Air Defense Artillery Officer','Ammunition Officer','Division Officer, Weapons Department','Division Officer, Weapons Department (Antisubmarine Weapons)','Division Officer, Weapons Department (Guided Missiles)','Division Officer, Weapons Department (Gunnery)','Field Artillery Officer','Field Artillery Senior Sergeant','Field Artillery Targeting Technician','Fire Control Officer (Surface-To-Air Missiles)','Ground Nuclear Weapons Assembly Officer','Guided Missile Test Officer, Air-Launched','HAWK Missile Air Defense Artillery','Low Altitude Air Defense Officer','Naval Gunfire Spotter','Naval Surface Fire Support Planner','Nuclear & Chemical Weapons Employment Officer','Nuclear Weapons Custodian','Ordnance Officer','PATRIOT Missile Air Defense Artillery','Short-Range Air Defense Artillery','Space And Missile Operations, Missile Combat Crew Officer','Strike Warfare/Missile Systems Officer','Strike Warfare/Missile Systems Officer (Surface-to-Air Missile)','Surface-to-Air Weapons Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-COMMAND_AND_CONTROL_CENTER_OFFICERS', 'source_onet_command_and_control_center_officers', 'Command and Control Center Officers', 'Command and Control Center Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Manage the operation of communications, detection, and weapons systems essential for controlling air, ground, and naval operations. Duties include managing critical communication links between air, naval, and ground forces; formulating and implementing emergency plans for natural and wartime disasters; coordinating emergency response teams and agencies; evaluating command center information and need for high-level military and government reporting; managing the operation of surveillance and detection systems; providing technical information and advice on capabilities and operational readiness; and directing operation of weapons targeting, firing, and launch computer systems.', ARRAY['AADC Plans Staff Officer','Advisor to Command in Combat','Air Battle Manager','Air Control/Anti-Air Warfare Officer','Air Defense Control Officer','Air Intercept Controller Supervisor','Air Liaison and Special Staff','Air Support Control Officer','Anti-Air Warfare Operations Officer','Antisubmarine Classification and Analysis Officer, Aviation','AOC AADC Chief of Operations Staff Officer','AOC AADC Director and Chief of Plans Staff Officer','AOC AADC Operations Staff Officer','Aoc Airspace Control Officer','Aoc Director Combat Operations Officer','Aoc Director Combat Plans Officer','AOC Director Intelligence Officer','Aoc Information Operations Staff Officer','Aoc Operations - Air Mobility / Logistics Chief','Aoc Operations - Air Mobility / Logistics Officer','Aoc Operations - Combat Search And Rescue Chief','Aoc Operations - Combat Search And Rescue Officer','Aoc Operations - Defensive Operations Officer','Aoc Operations - Intelligence Chief','Aoc Operations - Intelligence Officer','Aoc Operations - Naval And Amphibious Liaison Element Afloat Planning Liaison','Aoc Operations - Naval And Amphibious Liaison Element Member','Aoc Operations - Offensive Operations Officer','Aoc Operations - Special Operations Chief','Aoc Operations - Special Operations Officer','Aoc Operations - Time Sensitive / Critical Targeting Officer','Aoc Operations - Time Sensitive / Critical Targeting Officer Chief','Aoc Plans - Air Task Order / Air Control Order Production Officer','Aoc Plans - Guidance Apportionment And Targeting Officer','Aoc Plans - Guidance Apportionment And Targeting Officer Chief','AOC Plans - Intelligence Officer','AOC Plans - Intelligence Officer Chief','AOC Plans - Master Air Attack Planning Assistant Chief','Aoc Plans - Master Air Attack Planning Chief','Aoc Plans - Master Air Attack Planning Officer','Aoc Strategy Plans And Operational Assessment Officer','Aoc Strategy Plans And Operational Assessment Officer Chief','C4 Planner','Carrier Airborne Combat Information Center Officer','Combat Control Officer','Combat Information Center Officer','Combat Systems Officer','Command and Control','Command and Control Officer','Command and Control Systems Integrator']::text[], ARRAY['Command and Control Center Officers','AADC Plans Staff Officer','Advisor to Command in Combat','Air Battle Manager','Air Control/Anti-Air Warfare Officer','Air Defense Control Officer','Air Intercept Controller Supervisor','Air Liaison and Special Staff','Air Support Control Officer','Anti-Air Warfare Operations Officer','Antisubmarine Classification and Analysis Officer, Aviation','AOC AADC Chief of Operations Staff Officer','AOC AADC Director and Chief of Plans Staff Officer','AOC AADC Operations Staff Officer','Aoc Airspace Control Officer','Aoc Director Combat Operations Officer','Aoc Director Combat Plans Officer','AOC Director Intelligence Officer','Aoc Information Operations Staff Officer','Aoc Operations - Air Mobility / Logistics Chief','Aoc Operations - Air Mobility / Logistics Officer','Aoc Operations - Combat Search And Rescue Chief','Aoc Operations - Combat Search And Rescue Officer','Aoc Operations - Defensive Operations Officer','Aoc Operations - Intelligence Chief','Aoc Operations - Intelligence Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-INFANTRY_OFFICERS', 'source_onet_infantry_officers', 'Infantry Officers', 'Infantry Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Direct, train, and lead infantry units in ground combat operations. Duties include directing deployment of infantry weapons, vehicles, and equipment; directing location, construction, and camouflage of infantry positions and equipment; managing field communications operations; coordinating with armor, artillery, and air support units; performing strategic and tactical planning, including battle plan development; and leading basic reconnaissance operations.', ARRAY['Infantry Officer','Infantry Unit Leader','Infantry Weapons Officer']::text[], ARRAY['Infantry Officers','Infantry Officer','Infantry Unit Leader','Infantry Weapons Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
('ONET-SPECIAL_FORCES_OFFICERS', 'source_onet_special_forces_officers', 'Special Forces Officers', 'Special Forces Officers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Lead elite teams that implement unconventional operations by air, land, or sea during combat or peacetime. These activities include offensive raids, demolitions, reconnaissance, search and rescue, and counterterrorism. In addition to their combat training, special forces officers often have specialized training in swimming, diving, parachuting, survival, emergency medicine, and foreign languages. Duties include directing advanced reconnaissance operations and evaluating intelligence information; recruiting, training, and equipping friendly forces; leading raids and invasions on enemy territories; training personnel to implement individual missions and contingency plans; performing strategic and tactical planning for politically sensitive missions; and operating sophisticated communications equipment.', ARRAY['Advanced Seal Delivery System','Combatant Diver Officer','Combatant Diver Qualified (Officer)','Commanding Officer, Special Warfare Team','Control and Recovery, Combat Rescue','Control and Recovery, Special Tactics','Executive Officer, Special Warfare Team','Parachute/Combatant Diver Officer','Parachutist/Combatant Diver Qualified (Officer)','Sea-Air-Land Officer','Seal Delivery Vehicle Officer','Special Forces Officer','Special Forces Warrant Officer','Special Weapons Unit Officer']::text[], ARRAY['Special Forces Officers','Advanced Seal Delivery System','Combatant Diver Officer','Combatant Diver Qualified (Officer)','Commanding Officer, Special Warfare Team','Control and Recovery, Combat Rescue','Control and Recovery, Special Tactics','Executive Officer, Special Warfare Team','Parachute/Combatant Diver Officer','Parachutist/Combatant Diver Qualified (Officer)','Sea-Air-Land Officer','Seal Delivery Vehicle Officer','Special Forces Officer','Special Forces Warrant Officer','Special Weapons Unit Officer']::text[], ARRAY[]::text[], '{"source_imported_skills":[]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
